	controller.quotaByNamespace["kube-system"] = 50
	controller.quotaByNamespace["app"] = 20

	// Set policy counts
	controller.policyCountByNamespace["default"] = 5
	controller.policyCountByNamespace["kube-system"] = 30
	controller.policyCountByNamespace["app"] = 20

	// default namespace should allow more policies
	assert.NoError(t, controller.CheckQuota("default"))

