	}
	quotaResource := &mockResource[*cilium_v2.CiliumPolicyQuota]{
		events: make(chan resource.Event[*cilium_v2.CiliumPolicyQuota]),
	}

	controller := NewPolicyQuotaController(cnpResource, quotaResource)

	controller.policyCountByNamespace["default"] = 5
	controller.policyCountByNamespace["app"] = 10

	counts := controller.GetPolicyCounts()

	assert.Equal(t, 2, len(counts))
	assert.Equal(t, 5, counts["default"])
	assert.Equal(t, 10, counts["app"])
}

// TestGetQuotas tests the GetQuotas method
func TestGetQuotas(t *testing.T) {
	cnpResource := &mockResource[*cilium_v2.CiliumNetworkPolicy]{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}
	quotaResource := &mockResource[*cilium_v2.CiliumPolicyQuota]{
		events: make(chan resource.Event[*cilium_v2.CiliumPolicyQuota]),
	}

	controller := NewPolicyQuotaController(cnpResource, quotaResource)

	controller.quotaByNamespace["default"] = 100
	controller.quotaByNamespace["app"] = 50

	quotas := controller.GetQuotas()

	assert.Equal(t, 2, len(quotas))
	assert.Equal(t, 100, quotas["default"])
	assert.Equal(t, 50, quotas["app"])
}

// TestConcurrentAccess tests that the controller is thread-safe
func TestConcurrentAccess(t *testing.T) {
	cnpResource := &mockResource[*cilium_v2.CiliumNetworkPolicy]{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}
	quotaResource := &mockResource[*cilium_v2.CiliumPolicyQuota]{
		events: make(chan resource.Event[*cilium_v2.CiliumPolicyQuota]),
	}

	controller := NewPolicyQuotaController(cnpResource, quotaResource)

	controller.quotaByNamespace["default"] = 10
	controller.policyCountByNamespace["default"] = 5

	// Run concurrent reads and writes
	done := make(chan bool, 20)

	// Launch multiple goroutines doing concurrent operations
	for i := 0; i < 10; i++ {
		go func() {
			_ = controller.CheckQuota("default")
			done <- true
		}()
	}

	for i := 0; i < 10; i++ {
		go func() {
			_ = controller.GetPolicyCounts()
			_ = controller.GetQuotas()
			done <- true
		}()
	}

	// Wait for all goroutines to complete
	for i := 0; i < 20; i++ {
		<-done
	}
}

