package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota-controller")

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces
// per-namespace limits on the number of policies to prevent policy sprawl
// in multi-tenant clusters.
type PolicyQuotaController struct {
	logger logrus.FieldLogger

	// ciliumNetworkPolicies is the resource watcher for CiliumNetworkPolicy
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]

	// policyQuota is the resource watcher for CiliumPolicyQuota
	policyQuota resource.Resource[*cilium_v2.CiliumPolicyQuota]

	// mu protects the following fields
	mu sync.RWMutex

	// quotaByNamespace maps namespace names to their policy quotas
	quotaByNamespace map[string]int

	// policyCountByNamespace tracks the current number of policies per namespace
	policyCountByNamespace map[string]int
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
// If maxPerNamespace is provided (non-zero), it will be used as a default quota for all namespaces.
func NewPolicyQuotaController(
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	policyQuota resource.Resource[*cilium_v2.CiliumPolicyQuota],
) *PolicyQuotaController {
	return &PolicyQuotaController{
		logger:                 log,
		ciliumNetworkPolicies:  ciliumNetworkPolicies,
		policyQuota:            policyQuota,
		quotaByNamespace:       make(map[string]int),
		policyCountByNamespace: make(map[string]int),
	}
}

// Run starts the controller loop that watches CiliumNetworkPolicy and CiliumPolicyQuota resources.
// It blocks until the context is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) error {
	c.logger.Info("Starting PolicyQuotaController")

	// Create channels for events from both resources
	cnpEvents := c.ciliumNetworkPolicies.Events(ctx)
	quotaEvents := c.policyQuota.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			c.logger.Info("PolicyQuotaController stopped")
			return ctx.Err()

		case event, ok := <-cnpEvents:
			if !ok {
				cnpEvents = nil
				break
			}
			c.handleCNPEvent(event)

		case event, ok := <-quotaEvents:
			if !ok {
				quotaEvents = nil
				break
			}
			c.handleQuotaEvent(event)
		}
	}
}

// handleCNPEvent processes CiliumNetworkPolicy events
func (c *PolicyQuotaController) handleCNPEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	defer event.Done(nil)

	cnp := event.Object
	if cnp == nil {
		return
	}

	namespace := cnp.GetNamespace()

	c.mu.Lock()
	defer c.mu.Unlock()

	switch event.Kind {
	case resource.Upsert:
		// Increment the policy count for this namespace
		c.policyCountByNamespace[namespace]++
		c.logger.WithFields(logrus.Fields{
			"namespace":      namespace,
			"policy":         cnp.GetName(),
			"policyCount":    c.policyCountByNamespace[namespace],
			logfields.LogSubsys: "policy-quota-controller",
		}).Debug("CiliumNetworkPolicy created/updated")

	case resource.Delete:
		// Decrement the policy count for this namespace
		if count, exists := c.policyCountByNamespace[namespace]; exists && count > 0 {
			c.policyCountByNamespace[namespace]--
		}
		c.logger.WithFields(logrus.Fields{
			"namespace":      namespace,
			"policy":         cnp.GetName(),
			"policyCount":    c.policyCountByNamespace[namespace],
			logfields.LogSubsys: "policy-quota-controller",
		}).Debug("CiliumNetworkPolicy deleted")

	case resource.Sync:
		// Sync event signals that the store has synchronized
		c.logger.Debug("CiliumNetworkPolicy store synchronized")
	}
}

// handleQuotaEvent processes CiliumPolicyQuota events
func (c *PolicyQuotaController) handleQuotaEvent(event resource.Event[*cilium_v2.CiliumPolicyQuota]) {
	defer event.Done(nil)

	quota := event.Object
	if quota == nil {
		return
	}

	c.mu.Lock()
	defer c.mu.Unlock()

	switch event.Kind {
	case resource.Upsert:
		// Store the quota value
		c.quotaByNamespace[quota.Name] = quota.Spec.MaxPoliciesPerNamespace
		c.logger.WithFields(logrus.Fields{
			"quotaName":        quota.Name,
			"maxPolicies":      quota.Spec.MaxPoliciesPerNamespace,
			logfields.LogSubsys: "policy-quota-controller",
		}).Debug("CiliumPolicyQuota created/updated")

	case resource.Delete:
		// Remove the quota
		delete(c.quotaByNamespace, quota.Name)
		c.logger.WithFields(logrus.Fields{
			"quotaName":        quota.Name,
			logfields.LogSubsys: "policy-quota-controller",
		}).Debug("CiliumPolicyQuota deleted")

	case resource.Sync:
		c.logger.Debug("CiliumPolicyQuota store synchronized")
	}
}

// CheckQuota checks if adding a new policy to the given namespace would exceed the quota.
// It returns an error if the quota would be exceeded, nil otherwise.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	c.mu.RLock()
	defer c.mu.RUnlock()

	// If there's a namespace-specific quota, check against it
	if quota, exists := c.quotaByNamespace[namespace]; exists {
		currentCount := c.policyCountByNamespace[namespace]
		if currentCount >= quota {
			return fmt.Errorf(
				"policy quota exceeded for namespace %q: current=%d, max=%d",
				namespace, currentCount, quota,
			)
		}
	}

	return nil
}

// GetPolicyCounts returns a copy of the current policy counts per namespace (for testing/debugging)
func (c *PolicyQuotaController) GetPolicyCounts() map[string]int {
	c.mu.RLock()
	defer c.mu.RUnlock()

	counts := make(map[string]int)
	for ns, count := range c.policyCountByNamespace {
		counts[ns] = count
	}
	return counts
}

// GetQuotas returns a copy of the current quotas (for testing/debugging)
func (c *PolicyQuotaController) GetQuotas() map[string]int {
	c.mu.RLock()
	defer c.mu.RUnlock()

	quotas := make(map[string]int)
	for name, quota := range c.quotaByNamespace {
		quotas[name] = quota
	}
	return quotas
}

